import java.util.*;
import java.io.*;

public class Main {
    static final int TREEIFY_THRESHOLD = 8;
    static final int MIN_TREEIFY_CAPACITY = 64;

    static int spread(int h) {
        return h ^ (h >>> 16);
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int n = Integer.parseInt(br.readLine().trim());
        int k = Integer.parseInt(br.readLine().trim());
        TreeMap<Integer, Integer> counts = new TreeMap<>();
        int mask = n - 1;
        for (int i = 0; i < k; i++) {
            int key = Integer.parseInt(br.readLine().trim());
            int idx = mask & spread(Integer.valueOf(key).hashCode());
            counts.merge(idx, 1, Integer::sum);
        }
        StringBuilder sb = new StringBuilder();
        int max = 0;
        for (Map.Entry<Integer, Integer> e : counts.entrySet()) {
            int c = e.getValue();
            if (c > max) max = c;
            boolean treeify = c >= TREEIFY_THRESHOLD && n >= MIN_TREEIFY_CAPACITY;
            sb.append(e.getKey()).append(' ').append(c).append(' ')
              .append(treeify ? "TREEIFY" : "list").append('\n');
        }
        sb.append("max ").append(max).append('\n');
        System.out.print(sb);
    }
}

