import java.util.*;
import java.io.*;

public class Main {
    static final float LOAD_FACTOR = 0.75f;

    static int tableSizeFor(int cap) {
        int n = -1 >>> Integer.numberOfLeadingZeros(cap - 1);
        return (n < 0) ? 1 : (n + 1);
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int reqCap = Integer.parseInt(br.readLine().trim());
        long k = Long.parseLong(br.readLine().trim());
        long cap = tableSizeFor(Math.max(1, reqCap));
        long threshold = (long) Math.floor(cap * LOAD_FACTOR);
        StringBuilder sb = new StringBuilder();
        int rehashes = 0;
        for (long size = 1; size <= k; size++) {
            if (size > threshold) {
                long oldCap = cap;
                cap = cap << 1;
                threshold = (long) Math.floor(cap * LOAD_FACTOR);
                rehashes++;
                sb.append("resize ").append(oldCap).append(" -> ").append(cap)
                  .append(" at size ").append(size).append('\n');
            }
        }
        sb.append("final cap ").append(cap).append(" rehashes ").append(rehashes).append('\n');
        System.out.print(sb);
    }
}

